// --- Read event from Google Calendar node ---
const ev = ($('Google Calendar')?.first()?.json) || {};

// --- Prefer Meet link from conferenceData.entryPoints (video) ---
const meetFromEntry =
  ev?.conferenceData?.entryPoints?.find(e => e?.entryPointType === 'video')?.uri || '';
const hangoutLink = ev?.hangoutLink || '';
const htmlLink = ev?.htmlLink || '';

const meet = meetFromEntry || hangoutLink || htmlLink || '';

// --- Title ---
const title = ev?.summary || 'Linde Gas Connect with clients';

// --- Start / End / Timezone ---
// const tz  = ev?.start?.timeZone || Intl.DateTimeFormat().resolvedOptions().timeZone || 'Europe/Berlin';
const tz = 'Europe/Berlin';
const sISO = ev?.start?.dateTime || ev?.start?.date || '';
const eISO = ev?.end?.dateTime   || ev?.end?.date   || '';

// Helpers
const safeDate = (iso) => iso ? new Date(iso) : null;

const formatDate = (iso, zone) => {
  if (!iso) return 'Meeting date';
  try {
    return new Intl.DateTimeFormat('en-GB', {
      dateStyle: 'full',
      timeZone: zone
    }).format(safeDate(iso));
  } catch { return iso; }
};

const formatTime = (iso, zone, withZone = false) => {
  if (!iso) return '';
  try {
    return new Intl.DateTimeFormat('en-GB', {
      timeStyle: 'short',
      timeZone: zone,
      ...(withZone ? { timeZoneName: 'short' } : {})
    }).format(safeDate(iso));
  } catch { return iso; }
};

// --- Compose date + time range ---
const meetingDate = formatDate(sISO, tz);

// “10:00 – 14:00 (EST)” style
const startTime = formatTime(sISO, tz, false);
const endTime   = formatTime(eISO, tz, false);
const tzShort   = formatTime(sISO, tz, true).split(' ').slice(-1)[0] || tz; // pick "EST"/"CET" if present

let meetingTime = 'Time not set';
if (startTime && endTime) meetingTime = `${startTime} – ${endTime} (${tzShort})`;
else if (startTime)       meetingTime = `${startTime} (${tzShort})`;

// --- Button text ---
const isGoogleMeet = !!meet && meet.includes('meet.google.com');
const buttonText = isGoogleMeet ? 'Join Google Meet' : 'View Calendar Event';

// --- HTML ---
const html = `<!DOCTYPE html>
<html>
  <head>
    <style>
      .container { font-family: Arial, sans-serif; padding: 20px; background:#f8f8f8; border-radius:10px; max-width:600px; margin:auto; }
      .header { font-size:20px; font-weight:700; margin-bottom:10px; }
      .details { margin: 12px 0; }
      .meet-button { display:inline-block; padding:12px 20px; background:#006FBF; color:#fff; text-decoration:none; border-radius:8px; font-size:16px; font-weight:700; }
      .meet-button:hover { filter:brightness(1.05); }
      a { color:#006FBF; }
    </style>
  </head>
  <body>
    <div class="container">
      <div class="header">📅 You are invited to a meeting</div>
      <div class="details"><p><strong>Title:</strong> ${title}</p></div>
      <div class="details"><p><strong>Date:</strong> ${meetingDate}</p></div>
      <div class="details"><p><strong>Time:</strong> ${meetingTime}</p></div>

      <div class="details">
        <p><strong>${isGoogleMeet ? 'Join using Google Meet:' : 'View Event:'}</strong></p>
        <a class="meet-button" href="${meet}" target="_blank" rel="noopener" style="color: #ffffff !important;">${buttonText}</a>
        ${meet ? `<div style="margin-top:8px;font-size:12px;color:#666;">If the button doesn’t work, open: <a href="${meet}" target="_blank" rel="noopener" >${meet}</a></div>` : ''}
      </div>

      <div style="margin-top:18px; font-size:12px; color:#666;">
        This invite was sent by the Linde Gas AI-Powered Scheduling Assistant.
      </div>
    </div>
  </body>
</html>`;

return { html };

