      const confidence = $('downstream node').first().json?.confidence ?? null;

      // Phrases that indicate the agent is asking for clarification (no data yet)
      const CLARIFICATION_PHRASES = ['please provide', 'could you please', 'could you provide', 'please share', 'please let me know', 'kindly provide', 'what is your order', 'can you provide', 'can you share'];

      const responseText = String(typeof raw === 'string' && raw ? raw : 'No delivery status available');
      const lowerText = responseText.toLowerCase();
      const isClarification = CLARIFICATION_PHRASES.some(p => lowerText.includes(p));

      try {
        const maybe = typeof raw === 'string' ? JSON.parse(raw) : raw;

        if (maybe && (maybe.response_message || maybe.sources)) {
          const msg = String(maybe.response_message || '');
          const msgLower = msg.toLowerCase();
          const isMsgClarification = CLARIFICATION_PHRASES.some(p => msgLower.includes(p));
          const src = Array.isArray(maybe.sources) ? maybe.sources : [];
          return {
            response_message: msg,
            sources: isMsgClarification ? [] : src.map(s => ({
              doc_id: s?.doc_id || '',
              title: s?.title || '',
              file_url: s?.file_url || '',
              type: s?.type || intentType
            })),
            meta: { confidence }
          };
        }
      } catch (_) { /* ignore parse errors */ }

      return {
        response_message: responseText,
        sources: isClarification ? [] : [
          {
            doc_id: 'delivery_doc_001',
            title: 'Delivery Status Document',
            file_url: '',
            type: intentType
          }
        ],
        meta: { confidence }
      };
